245→    fun getCollectionDirectory() =
246→        // Allow execution if AnkiDroidApp.instance is not initialized
247→        File(CollectionHelper.getCurrentAnkiDroidDirectoryOptionalContext(AnkiDroidApp.sharedPrefs()) { AnkiDroidApp.instance })
