249→    /** Ensures the AnkiDroid directory is created, then returns the path to the collection file
250→     * inside it. */
251→    fun collectionPathInValidFolder(): String {
252→        val dir = getCollectionDirectory().path
253→        CollectionHelper.initializeAnkiDroidDirectory(dir)
