256→
257→    /**
258→     * Like [withQueue], but can be used in a synchronous context.
259→     *
260→     * Note: Because [runBlocking] inside `RobolectricTest.runTest` will lead to
261→     * deadlocks, this will not block when run under Robolectric,
262→     * and there is no guarantee about concurrent access.
263→     */
264→    private fun <T> blockForQueue(block: CollectionManager.() -> T): T {
265→        return if (isRobolectric) {
266→            block(this)
267→        } else {
268→            runBlocking {
269→                withQueue(block)
270→            }
271→        }
272→    }
273→
274→    fun closeCollectionBlocking() {
275→        runBlocking { ensureClosed() }
276→    }
277→
278→    /**
279→     * Returns a reference to the open collection. This is not
280→     * safe, as code in other threads could open or close
281→     * the collection while the reference is held. [withCol]
282→     * is a better alternative.
283→     */
284→    fun getColUnsafe(): Collection {
285→        return logUIHangs {
286→            blockForQueue {
287→                ensureOpenInner()
288→                collection!!
289→            }
290→        }
291→    }
292→
293→    /**
294→     Execute [block]. If it takes more than 100ms of real time, Timber an error like:
295→     > Blocked main thread for 2424ms: com.ichi2.anki.DeckPicker.onCreateOptionsMenu(DeckPicker.kt:624)
296→     */
297→    // using TimeManager breaks a sched test that makes assumptions about the time, so we
298→    // access the time directly
299→    @SuppressLint("DirectSystemCurrentTimeMillisUsage")
300→    private fun <T> logUIHangs(block: () -> T): T {
301→        val start = System.currentTimeMillis()
302→        return block().also {
303→            val elapsed = System.currentTimeMillis() - start
304→            if (Threads.isOnMainThread && elapsed > 100) {
305→                val stackTraceElements = Thread.currentThread().stackTrace
306→                // locate the probable calling file/line in the stack trace, by filtering
307→                // out our own code, and standard dalvik/java.lang stack frames
308→                val caller = stackTraceElements.filter {
309→                    val klass = it.className
310→                    val toCheck = listOf(
311→                        "CollectionManager",
312→                        "dalvik",
313→                        "java.lang",
314→                        "CollectionHelper",
315→                        "AnkiActivity"
316→                    )
317→                    for (text in toCheck) {
318→                        if (text in klass) {
319→                            return@filter false
320→                        }
321→                    }
322→                    true
323→                }.first()
324→                Timber.w("blocked main thread for %dms:\n%s", elapsed, caller)
325→            }
326→        }
327→    }
328→
329→    /**
330→     * True if the collection is open. Unsafe, as it has the potential to race.
331→     */
332→    fun isOpenUnsafe(): Boolean {
333→        return logUIHangs {
334→            blockForQueue {
335→                if (emulateOpenFailure) {
336→                    false
337→                } else {
338→                    collection?.dbClosed == false
339→                }
340→            }
341→        }
342→    }
