175→    /**
176→     * Open the backend if it's not already open.
177→     */
178→    private suspend fun ensureBackend() {
179→        withQueue {
180→            ensureBackendInner()
181→        }
182→    }
183→
184→    /** See [ensureBackend]. This must only be run inside the queue. */
185→    private fun ensureBackendInner() {
186→        if (backend == null) {
187→            backend = BackendFactory.getBackend()
188→        }
189→    }
190→
191→    /**
192→     * If the collection is open, close it.
193→     */
194→    suspend fun ensureClosed() {
195→        withQueue {
196→            ensureClosedInner()
197→        }
198→    }
199→
200→    /** See [ensureClosed]. This must only be run inside the queue. */
201→    private fun ensureClosedInner() {
202→        if (collection == null) {
203→            return
204→        }
205→        try {
206→            collection!!.close()
207→        } catch (exc: Exception) {
208→            Timber.e("swallowing error on close: $exc")
209→        }
210→        collection = null
211→    }
212→
213→    /**
214→     * Open the collection, if it's not already open.
215→     *
216→     * Automatically called by [withCol]. Can be called directly to ensure collection
217→     * is loaded at a certain point in time, or to ensure no errors occur.
218→     */
219→    private suspend fun ensureOpen() {
220→        withQueue {
221→            ensureOpenInner()
222→        }
223→    }
224→
225→    /** See [ensureOpen]. This must only be run inside the queue. */
226→    private fun ensureOpenInner() {
227→        ensureBackendInner()
228→        if (emulateOpenFailure) {
229→            throw BackendException.BackendDbException.BackendDbLockedException(backendError {})
230→        }
231→        if (collection == null || collection!!.dbClosed) {
232→            val path = collectionPathInValidFolder()
233→            collection =
234→                collection(path, log = !disableLogFile, backend)
235→        }
236→    }
